# Enable local file sharing (required for openfiles command to work properly)\n# Note: This might require administrator privileges\n\n# Try to list open files in our build directory\nWrite-Host \"Attempting to list open files in the build directory...\"\n\n# First, enable file sharing if not already enabled\n# This command might fail if not run as administrator, but we'll try anyway\ntry {\n    openfiles /local on 2>$null\n} catch {\n    Write-Host \"Could not enable local file sharing. This is normal if not running as administrator.\"\n}\n\n# Now try to find open files in our directory\ntry {\n    $result = openfiles /query | Select-String -Pattern \"C:\\Users\\rowdy\\AndroidStudioProjects\\ROSTRY\\app\\build\"\n    if ($result) {\n        Write-Host \"Found open files in the build directory:\"\n        $result\n    } else {\n        Write-Host \"No open files found in the build directory using openfiles command.\"\n        Write-Host \"This might be because:\"\n        Write-Host \"1. No files are currently open\"\n        Write-Host \"2. The openfiles command requires administrator privileges\"\n        Write-Host \"3. Another method is being used to lock the files\"\n    }\n} catch {\n    Write-Host \"Could not query open files. This is normal if not running as administrator.\"\n}\n\nWrite-Host \"Common processes that might be locking Android build files:\"\nWrite-Host \"- Android Studio\"\nWrite-Host \"- Gradle daemon\"\nWrite-Host \"- ADB (Android Debug Bridge)\"\nWrite-Host \"- Running emulator\"\nWrite-Host \"- Command prompt or terminal with build directory as current directory\"
